package com.finguard.fraud.config;import com.finguard.security.*;import org.springframework.beans.factory.annotation.Value;import org.springframework.context.annotation.*;import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;import org.springframework.security.config.annotation.web.builders.HttpSecurity;import org.springframework.security.web.SecurityFilterChain;
@Configuration @EnableMethodSecurity public class SecurityConfig extends SecuritySupport {@Bean JwtTokenVerifier jwtTokenVerifier(@Value("${security.jwt.secret}")String secret){return new JwtTokenVerifier(secret);}@Bean JwtAuthenticationFilter jwtAuthenticationFilter(JwtTokenVerifier v){return new JwtAuthenticationFilter(v);}@Bean SecurityFilterChain filterChain(HttpSecurity http,JwtAuthenticationFilter f)throws Exception{return secure(http,f,"/actuator/**","/v3/api-docs/**","/swagger-ui/**","/swagger-ui.html");}}
